files.flake.nix:
{
  description = "mofaflex - Factor Analysis Models";

  inputs = {
    nixpkgs.url = "github:NixOS/nixpkgs/nixos-unstable";
    flake-utils.url = "github:numtide/flake-utils";
  };

  outputs = { self, nixpkgs, flake-utils }:
    flake-utils.lib.eachDefaultSystem (system:
      let
        pkgs = nixpkgs.legacyPackages.${system};
        python = pkgs.python3;
        pythonWithPackages = python.withPackages (ps: [
          ps.numpy ps.scipy ps.pandas ps.anndata ps.session-info2
          ps.torch ps.pyro-ppl ps.scikit-learn ps.statsmodels
          ps.h5py ps.plotnine ps.mizani ps.dtw-python ps.tqdm
          ps.platformdirs ps.packaging ps.gpytorch ps.array-api-compat
          ps.mudata
        ]);
        customPackages = {
          mofaflex = ps: (import ./main { inherit ps; }).mofaflex;
          mudata = ps: (import ./dep1 { inherit ps; }).mudata;
        };
        finalPackages = let
          ps = python.pkgs;
          allDeps = ps: with ps; [
            numpy scipy pandas anndata session-info2 torch pyro-ppl
            scikit-learn statsmodels h5py plotnine mizani dtw-python tqdm
            platformdirs packaging gpytorch array-api-compat mudata
          ];
        in {
          mofaflex = pythonWithPackages (ps: allDeps ps);
          mudata = pythonWithPackages (ps: allDeps ps);
        };
      in {
        packages = {
          inherit (finalPackages) mofaflex mudata;
          default = finalPackages.mofaflex;
        };
        devShells.default = pkgs.mkShell {
          name = "mofaflex-dev";
          buildInputs = with pkgs; [
            python
            python.pkgs.pip
            python.pkgs.setuptools
            python.pkgs.wheel
          ];
        };
      }
    );
}

files.main/default.nix:
{
  lib,
  buildPythonPackage,
  fetchPypi,
  ps,
  # dependencies provided by caller via ps argument
}:
let
  pname = "mofaflex";
  version = "0.1.0.post1";
  src = fetchPypi {
    inherit pname version;
    hash = "sha256-9J1QyZ0VlC4r5v0P0KqZ5Q7J3n0L2Z4X9Y8W7V6U0K4=";
  };

  # Build dependencies (if needed, empty here since using pyproject.toml)
  build-system = [];

  # Runtime dependencies extracted from requires_dist
  dependencies = with ps; [
    anndata array-api-compat dtw-python gpytorch h5py mizani mudata numpy
    packaging pandas platformdirs plotnine pyro-ppl scikit-learn scipy
    session-info2 statsmodels torch tqdm
  ];

  pythonImportsCheck = [ "mofaflex" ];

  doCheck = false; # Tests require fixtures and are skipped per instructions
in
buildPythonPackage {
  inherit pname version src build-system dependencies pythonImportsCheck doCheck;

  meta = with lib; {
    description = "Factor Analysis Models";
    longDescription = ''
      MOFA-FLEX is a versatile factor analysis framework designed to streamline
      the construction and training of complex matrix factorisation models for omics data.
    '';
    homepage = "https://mofaflex.readthedocs.io";
    license = licenses.bsd3;
    maintainers = with maintainers; [ ];
    pythonImportsCheck = [ "mofaflex" ];
  };
}

